import{_ as t,o as i,c as a,ae as r}from"./chunks/framework.BGHOrOyn.js";const p=JSON.parse(`{"title":"Sentry's take on Code Reviews","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/principles-and-practices/code-reviews/sentrys-take-on-code-reviews.md","filePath":"software-engineering/principles-and-practices/code-reviews/sentrys-take-on-code-reviews.md"}`),o={name:"software-engineering/principles-and-practices/code-reviews/sentrys-take-on-code-reviews.md"};function s(n,e,l,h,d,c){return i(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="sentry-s-take-on-code-reviews" tabindex="-1">Sentry&#39;s take on Code Reviews <a class="header-anchor" href="#sentry-s-take-on-code-reviews" aria-label="Permalink to &quot;Sentry&#39;s take on Code Reviews&quot;">​</a></h1><p><a href="https://develop.sentry.dev/code-review/" target="_blank" rel="noreferrer">https://develop.sentry.dev/code-review/</a></p><h2 id="code-review" tabindex="-1">Code Review <a class="header-anchor" href="#code-review" aria-label="Permalink to &quot;Code Review&quot;">​</a></h2><p>Code review is mandatory at Sentry. This adds overhead to each change, but ensures that simple, often overlooked problems are more easily avoided. Code review helps build shared context and collective ownership. It is also an opportunity to collaborate with other teams. Finally, code review can identify several classes of problem before customers are exposed to them.</p><p>Code review is managed via GitHub’s Pull Requests (see below for rationale). Templates may exist on repositories, but if they do not, consider <a href="https://help.github.com/articles/creating-a-pull-request-template-for-your-repository/" target="_blank" rel="noreferrer">creating one</a>.</p><h3 id="who-should-be-reviewing-code" tabindex="-1">Who should be reviewing code? <a href="#who-should-be-reviewing-code" id="who-should-be-reviewing-code"></a> <a class="header-anchor" href="#who-should-be-reviewing-code" aria-label="Permalink to &quot;Who should be reviewing code? &lt;a href=&quot;#who-should-be-reviewing-code&quot; id=&quot;who-should-be-reviewing-code&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>All engineers should be reviewing code. As you gain more experience and context on the products we build and technologies we use, you can provide valuable feedback to other engineers who may be working in areas that are new to them but familiar to you.</p><p>Code review is an opportunity to improve your mentoring and communication skills. Code review can have the important function of teaching engineers about the languages, frameworks and technologies we use in a collaborative environment that is about the changes being made.</p><p>When creating a pull request, reference any tickets or Sentry issues which are being addressed. Additionally <strong>@mention</strong> an appropriate team (or teams) for review.</p><h3 id="why-pull-requests" tabindex="-1">Why Pull Requests <a href="#why-pull-requests" id="why-pull-requests"></a> <a class="header-anchor" href="#why-pull-requests" aria-label="Permalink to &quot;Why Pull Requests &lt;a href=&quot;#why-pull-requests&quot; id=&quot;why-pull-requests&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Because Sentry is an open source project maintained via GitHub we want to ensure that the barrier to entry for external contributions is minimal. By using GitHub features when possible, we make it easy for developers familiar with other projects on GitHub. While GitHub’s tools <a href="http://cra.mr/2014/05/03/on-pull-requests" target="_blank" rel="noreferrer">aren’t always the best</a>, they work well enough.</p><h4 id="github-teams" tabindex="-1">GitHub Teams <a href="#github-teams" id="github-teams"></a> <a class="header-anchor" href="#github-teams" aria-label="Permalink to &quot;GitHub Teams &lt;a href=&quot;#github-teams&quot; id=&quot;github-teams&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>The following teams are defined in GitHub and can be used when creating Pull Requests:</p><ul><li><a href="https://github.com/orgs/getsentry/teams/app-backend" target="_blank" rel="noreferrer">@getsentry/app-backend</a></li><li><a href="https://github.com/orgs/getsentry/teams/app-frontend" target="_blank" rel="noreferrer">@getsentry/app-frontend</a></li><li><a href="https://github.com/orgs/getsentry/teams/infrastructure" target="_blank" rel="noreferrer">@getsentry/infrastructure</a></li><li><a href="https://github.com/orgs/getsentry/teams/ops" target="_blank" rel="noreferrer">@getsentry/ops</a></li><li><a href="https://github.com/orgs/getsentry/teams/app" target="_blank" rel="noreferrer">@getsentry/app</a> – the entire product team, use sparingly</li></ul><p>Sentry has more than 200 public repositories. A more comprehensive list of teams and repositories can be found in the <a href="https://open.sentry.io/structure/" target="_blank" rel="noreferrer">Sentry Structure</a> overview.</p><h3 id="commit-guidelines" tabindex="-1">Commit Guidelines <a href="#commit-guidelines" id="commit-guidelines"></a> <a class="header-anchor" href="#commit-guidelines" aria-label="Permalink to &quot;Commit Guidelines &lt;a href=&quot;#commit-guidelines&quot; id=&quot;commit-guidelines&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>See the <a href="https://develop.sentry.dev/commit-messages/" target="_blank" rel="noreferrer">Commit Messages</a> guide.</p><h3 id="code-reviews-are-for" tabindex="-1">Code Reviews are for … <a href="#code-reviews-are-for" id="code-reviews-are-for"></a> <a class="header-anchor" href="#code-reviews-are-for" aria-label="Permalink to &quot;Code Reviews are for … &lt;a href=&quot;#code-reviews-are-for&quot; id=&quot;code-reviews-are-for&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><h4 id="identifying-problematic-code" tabindex="-1">Identifying problematic code <a href="#identifying-problematic-code" id="identifying-problematic-code"></a> <a class="header-anchor" href="#identifying-problematic-code" aria-label="Permalink to &quot;Identifying problematic code &lt;a href=&quot;#identifying-problematic-code&quot; id=&quot;identifying-problematic-code&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Above all, a code review should try to identify potential bugs that could cause the application to break – either now, or in the future.</p><ul><li>Uncaught runtime exceptions (e.g. potential for an index to be out of bounds)</li><li>Obvious performance bottlenecks (e.g. <code>O(n^2)</code> where <code>n</code> is unbounded)</li><li>Code alters behavior elsewhere in an unanticipated way</li><li>API changes are not backwards compatible (e.g. renaming or removing a key)</li><li>Complex ORM interactions that may have unexpected query generation/performance</li><li>Security vulnerabilities</li><li>Missing or incorrect Permissions or Access Control.</li></ul><h4 id="improving-design" tabindex="-1">Improving Design <a href="#improving-design" id="improving-design"></a> <a class="header-anchor" href="#improving-design" aria-label="Permalink to &quot;Improving Design &lt;a href=&quot;#improving-design&quot; id=&quot;improving-design&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>When reviewing code, consider if the interactions of the various pieces in the change make sense together. If you are familiar with the project, do the changes conflict with other requirements or goals? Could any of the methods being added be promoted to module level methods? Are methods being passed properties of objects when they could be passed the entire object?</p><h4 id="tests-included" tabindex="-1">Tests Included <a href="#tests-included" id="tests-included"></a> <a class="header-anchor" href="#tests-included" aria-label="Permalink to &quot;Tests Included &lt;a href=&quot;#tests-included&quot; id=&quot;tests-included&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Look for tests. There should be functional tests, integration tests or end-to-end tests covering the changes. If not, ask for them. At Sentry we rely on our test suite to maintain a high quality bar and ship rapidly.</p><p>When reviewing tests double check that the tests cover the requirements of the project or that they cover the defect being fixed. Tests should avoid branching and looping as much as possible to prevent bugs in the test code from gaining a foothold.</p><p>Functional tests that simulate how a user would call our APIs or use our UX are key to preventing regressions and avoiding brittle tests that are coupled to the internals of the products we ship.</p><p>Tests are also the ideal place to ensure that the changes have considered permissions and access control logic.</p><h4 id="assessing-and-approving-long-term-impact" tabindex="-1">Assessing and approving long-term impact <a href="#assessing-and-approving-long-term-impact" id="assessing-and-approving-long-term-impact"></a> <a class="header-anchor" href="#assessing-and-approving-long-term-impact" aria-label="Permalink to &quot;Assessing and approving long-term impact &lt;a href=&quot;#assessing-and-approving-long-term-impact&quot; id=&quot;assessing-and-approving-long-term-impact&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>If you’re making significant architectural, schema, or build changes that will have long-term ramifications to the software or data, it is necessary to solicit a senior engineer’s acknowledgment and blessing.</p><ul><li>Large refactors</li><li>Database schema changes, like adding or removing columns and tables</li><li>API changes (including JSON schema changes)</li><li>Adopting new frameworks, libraries, or tools</li><li>New product behavior that may permanently alter performance characteristics moving forward</li></ul><h4 id="double-checking-expected-behavior" tabindex="-1">Double-checking expected behavior <a href="#double-checking-expected-behavior" id="double-checking-expected-behavior"></a> <a class="header-anchor" href="#double-checking-expected-behavior" aria-label="Permalink to &quot;Double-checking expected behavior &lt;a href=&quot;#double-checking-expected-behavior&quot; id=&quot;double-checking-expected-behavior&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>The reviewer should make a genuine attempt to double-check that the goals of the PR appear to be satisfied by the code submitted. This requires the submitter to write a good description of the expected behavior, and why. <em>See also: Guidelines for submitters</em> <em>below</em>.</p><h4 id="information-sharing-and-professional-development" tabindex="-1">Information sharing and professional development <a href="#information-sharing-and-professional-development" id="information-sharing-and-professional-development"></a> <a class="header-anchor" href="#information-sharing-and-professional-development" aria-label="Permalink to &quot;Information sharing and professional development &lt;a href=&quot;#information-sharing-and-professional-development&quot; id=&quot;information-sharing-and-professional-development&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Code reviews are an opportunity for more people to understand forthcoming code changes, so that they might in turn teach others down the road, and be in a position to fix something if/when the original author is not be available.</p><p>Additionally, code reviews are an opportunity to learn about new techniques or approaches, and be exposed to code you might otherwise not have an opportunity to browse.</p><h4 id="reducing-code-complexity" tabindex="-1">Reducing code complexity <a href="#reducing-code-complexity" id="reducing-code-complexity"></a> <a class="header-anchor" href="#reducing-code-complexity" aria-label="Permalink to &quot;Reducing code complexity &lt;a href=&quot;#reducing-code-complexity&quot; id=&quot;reducing-code-complexity&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Research shows that LOC is correlated with a higher bug count. If reviewers see an easy opportunity to significantly reduce the amount of code that is submitted, they should suggest a different approach.</p><p>For example, if a submitter has written a <code>for</code> loop to find an item in an array:</p><p>TextCopied</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> arr.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">length</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">++</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (arr[i] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">===</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;thingiwant&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> undefined</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>It’s fair game to suggest they instead use:</p><p>TextCopied</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> arr</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ===</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;thingiwant&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>This is a mostly objective improvement: there are fewer variables, fewer statements, and fewer branches, and the method name <code>find</code> communicates intent. Suggesting these types of uncontroversial improvements is encouraged.</p><p>Be careful though – it’s easy to go down a rabbit hole of re-writing code to be as small as possible, and in the end winding up with something ultimately more complicated. Be pragmatic and strive to reach a good balance. <em>See also: “Code reviews are not for getting it perfect” below.</em></p><h4 id="enforcing-coding-standards" tabindex="-1">Enforcing coding standards <a href="#enforcing-coding-standards" id="enforcing-coding-standards"></a> <a class="header-anchor" href="#enforcing-coding-standards" aria-label="Permalink to &quot;Enforcing coding standards &lt;a href=&quot;#enforcing-coding-standards&quot; id=&quot;enforcing-coding-standards&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>As much as possible, we use automation to enforce code style and test coverage, but there are exceptions that cannot necessarily be automated (or perhaps more accurately, we haven’t automated them <em>yet</em>):</p><ul><li>Variable, file, metric, and logger names are sensible, readable, and consistent with existing code</li><li>Migrations have a deployment plan</li><li>Unused or superfluous code isn’t committed accidentally</li></ul><h3 id="code-reviews-are-not-for" tabindex="-1">Code Reviews are not for … <a href="#code-reviews-arenotfor" id="code-reviews-arenotfor"></a> <a class="header-anchor" href="#code-reviews-are-not-for" aria-label="Permalink to &quot;Code Reviews are not for … &lt;a href=&quot;#code-reviews-arenotfor&quot; id=&quot;code-reviews-arenotfor&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><h4 id="passing-responsibility-onto-the-reviewer" tabindex="-1">Passing responsibility onto the reviewer <a href="#passing-responsibility-onto-the-reviewer" id="passing-responsibility-onto-the-reviewer"></a> <a class="header-anchor" href="#passing-responsibility-onto-the-reviewer" aria-label="Permalink to &quot;Passing responsibility onto the reviewer &lt;a href=&quot;#passing-responsibility-onto-the-reviewer&quot; id=&quot;passing-responsibility-onto-the-reviewer&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>It is not the responsibility of the reviewer that your code is correct, is bug free, or achieves its goals. Reviewers are there to help you, but if something is wrong, it’s your responsibility to correct it.</p><h4 id="boasting-about-your-programming-knowledge" tabindex="-1">Boasting about your programming knowledge <a href="#boasting-about-your-programming-knowledge" id="boasting-about-your-programming-knowledge"></a> <a class="header-anchor" href="#boasting-about-your-programming-knowledge" aria-label="Permalink to &quot;Boasting about your programming knowledge &lt;a href=&quot;#boasting-about-your-programming-knowledge&quot; id=&quot;boasting-about-your-programming-knowledge&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>As a reviewer, try to stick to objective improvements and make a best-intent assumption that the submitter has done their homework. Sentry is a No Flex Zone™.</p><h4 id="introducing-long-term-architectural-changes-for-the-first-time" tabindex="-1">Introducing long-term architectural changes for the first time <a href="#introducing-long-term-architectural-changes-for-the-first-time" id="introducing-long-term-architectural-changes-for-the-first-time"></a> <a class="header-anchor" href="#introducing-long-term-architectural-changes-for-the-first-time" aria-label="Permalink to &quot;Introducing long-term architectural changes for the first time &lt;a href=&quot;#introducing-long-term-architectural-changes-for-the-first-time&quot; id=&quot;introducing-long-term-architectural-changes-for-the-first-time&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>While code reviews are great for discussion, they’re not the place to introduce large, long-term changes for the first time. Before dropping a PR that implements those changes, you should write a proposal and reach out to the relevant parties beforehand.</p><h4 id="getting-it-perfect" tabindex="-1">Getting it perfect <a href="#getting-it-perfect" id="getting-it-perfect"></a> <a class="header-anchor" href="#getting-it-perfect" aria-label="Permalink to &quot;Getting it perfect &lt;a href=&quot;#getting-it-perfect&quot; id=&quot;getting-it-perfect&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Code reviews are expensive. Every time you request a change, you’re probably delaying that PR by 24 hours or more. This can severely inhibit our ability to move fast.</p><p>The goal of code reviews is to <strong>reduce risk</strong>, not to produce perfect code. It’s okay to ship code in stages, and to commit to improving something later. If you’re thinking – <em>if we don’t get it correct up-front, we’ll never come back to it</em> – consider that if it never needs coming back to, perhaps those changes were never necessary in the first place.</p><blockquote><p>Perfect is the enemy of the good. – Voltaire, probably</p></blockquote><p>Please be pragmatic, and consider the cost of each incremental request for changes.</p><h3 id="guidelines-for-submitters" tabindex="-1">Guidelines for <em>Submitters</em> <a href="#guidelines-forsubmitters" id="guidelines-forsubmitters"></a> <a class="header-anchor" href="#guidelines-for-submitters" aria-label="Permalink to &quot;Guidelines for _Submitters_ &lt;a href=&quot;#guidelines-forsubmitters&quot; id=&quot;guidelines-forsubmitters&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><h4 id="try-to-organize-your-work-in-a-way-that-makes-it-conducive-to-review" tabindex="-1">Try to organize your work in a way that makes it conducive to review <a href="#try-to-organize-your-work-in-a-way-that-makes-it-conducive-to-review" id="try-to-organize-your-work-in-a-way-that-makes-it-conducive-to-review"></a> <a class="header-anchor" href="#try-to-organize-your-work-in-a-way-that-makes-it-conducive-to-review" aria-label="Permalink to &quot;Try to organize your work in a way that makes it conducive to review &lt;a href=&quot;#try-to-organize-your-work-in-a-way-that-makes-it-conducive-to-review&quot; id=&quot;try-to-organize-your-work-in-a-way-that-makes-it-conducive-to-review&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li>Ideally, a pull request is limited to only a single feature or behavior change.</li><li>This might feel like more work up-front, but it can make code review faster, reduce risk by letting you ship in stages, and ultimately end up being quicker.</li></ul><h4 id="describe-what-your-pr-does-in-a-few-sentences-in-the-description-field" tabindex="-1">Describe what your PR does in a few sentences in the description field <a href="#describe-what-your-pr-does-in-a-few-sentences-in-the-description-field" id="describe-what-your-pr-does-in-a-few-sentences-in-the-description-field"></a> <a class="header-anchor" href="#describe-what-your-pr-does-in-a-few-sentences-in-the-description-field" aria-label="Permalink to &quot;Describe what your PR does in a few sentences in the description field &lt;a href=&quot;#describe-what-your-pr-does-in-a-few-sentences-in-the-description-field&quot; id=&quot;describe-what-your-pr-does-in-a-few-sentences-in-the-description-field&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li>Additionally explain <em><strong>why</strong></em> we’re making these changes.</li><li>If applicable, explain why other approaches were explored but not settled on.</li><li>This gives the reviewer context, and prevents them going down the same rabbit holes that that submitter may have already explored when creating the code.</li></ul><h4 id="annotate-specific-lines-in-your-pr" tabindex="-1">Annotate specific lines in your PR <a href="#annotate-specific-lines-in-your-pr" id="annotate-specific-lines-in-your-pr"></a> <a class="header-anchor" href="#annotate-specific-lines-in-your-pr" aria-label="Permalink to &quot;Annotate specific lines in your PR &lt;a href=&quot;#annotate-specific-lines-in-your-pr&quot; id=&quot;annotate-specific-lines-in-your-pr&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li>If you can, give context to specific lines of code that could use elaboration.</li><li>Example: <a href="https://github.com/getsentry/sentry/pull/6330#discussion_r144441272" target="_blank" rel="noreferrer">getsentry/sentry#6330</a></li></ul><h4 id="where-appropriate-label-in-progress-prs-as-wip-work-in-progress-for-early-feedback" tabindex="-1">Where appropriate, label in-progress PRs as WIP (work in progress) for early feedback <a href="#where-appropriate-label-in-progress-prs-as-wip-work-in-progress-for-early-feedback" id="where-appropriate-label-in-progress-prs-as-wip-work-in-progress-for-early-feedback"></a> <a class="header-anchor" href="#where-appropriate-label-in-progress-prs-as-wip-work-in-progress-for-early-feedback" aria-label="Permalink to &quot;Where appropriate, label in-progress PRs as WIP (work in progress) for early feedback &lt;a href=&quot;#where-appropriate-label-in-progress-prs-as-wip-work-in-progress-for-early-feedback&quot; id=&quot;where-appropriate-label-in-progress-prs-as-wip-work-in-progress-for-early-feedback&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li>Labeling your work as WIP helps set expectations about the state of the PR.</li><li>WIP PRs are good for having someone check-in to make sure you’re on the right path.</li><li>Additionally, this is an opportunity to verify CI passes before involving a reviewer.</li></ul><h4 id="be-your-own-first-reviewer" tabindex="-1">Be your own first reviewer <a href="#be-your-own-first-reviewer" id="be-your-own-first-reviewer"></a> <a class="header-anchor" href="#be-your-own-first-reviewer" aria-label="Permalink to &quot;Be your own first reviewer &lt;a href=&quot;#be-your-own-first-reviewer&quot; id=&quot;be-your-own-first-reviewer&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li>After you’ve put up your PR on GitHub, walk through the code yourself, before assigning an external reviewer.</li><li>You’ll often catch code mistakes you didn’t see when writing it.</li><li>This is also a good time to leave comments and refresh your memory in order to write a more helpful description.</li></ul><h4 id="assign-no-more-than-1-3-reviewers" tabindex="-1">Assign no more than 1-3 reviewers <a href="#assign-no-more-than-1-3-reviewers" id="assign-no-more-than-1-3-reviewers"></a> <a class="header-anchor" href="#assign-no-more-than-1-3-reviewers" aria-label="Permalink to &quot;Assign no more than 1-3 reviewers &lt;a href=&quot;#assign-no-more-than-1-3-reviewers&quot; id=&quot;assign-no-more-than-1-3-reviewers&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li>It’s tempting to want to involve as many people as possible, but it can often be distracting, and create a situation where nobody’s clear on who should actually perform the review.</li><li>If your work spans multiple teams (and thus, many reviewers), consider breaking up your PR into multiple compatible patches (e.g. a back-end change and a front-end change).</li><li>Note: if you don’t know who from a team to assign, you can assign teams like @workflow and @platform.</li></ul><h4 id="avoid-rebasing-unnecessarily" tabindex="-1">Avoid rebasing unnecessarily <a href="#avoid-rebasing-unnecessarily" id="avoid-rebasing-unnecessarily"></a> <a class="header-anchor" href="#avoid-rebasing-unnecessarily" aria-label="Permalink to &quot;Avoid rebasing unnecessarily &lt;a href=&quot;#avoid-rebasing-unnecessarily&quot; id=&quot;avoid-rebasing-unnecessarily&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li>After a rebase, previous review comments will be orphaned from their now non-existent parent commits, making review more difficult</li><li>Rewriting history makes it difficult for reviewers to isolate the scope of their review</li></ul><h4 id="let-reviewers-know-that-you-ve-made-changes" tabindex="-1">Let reviewers know that you’ve made changes <a href="#let-reviewers-know-that-youve-made-changes" id="let-reviewers-know-that-youve-made-changes"></a> <a class="header-anchor" href="#let-reviewers-know-that-you-ve-made-changes" aria-label="Permalink to &quot;Let reviewers know that you’ve made changes &lt;a href=&quot;#let-reviewers-know-that-youve-made-changes&quot; id=&quot;let-reviewers-know-that-youve-made-changes&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li>Request review again via the &quot;Reviewers&quot; dropdown (There should be a yellow dot next to their name again).</li><li>Don’t rely on reviewers&#39; mind-reading skills to know that you’re ready to have them look things over again.</li><li>If you resolve a point of actionable feedback, it&#39;s helpful to leave a comment to let the reviewer know that it was addressed, ideally with a reference to the commit that addressed it, e.g. <a href="https://github.com/getsentry/sentry/pull/6683#discussion_r155121800" target="_blank" rel="noreferrer">getsentry/sentry#6683 (comment)</a></li></ul><h3 id="guidelines-for-reviewers" tabindex="-1">Guidelines for <em>Reviewers</em> <a href="#guidelines-forreviewers" id="guidelines-forreviewers"></a> <a class="header-anchor" href="#guidelines-for-reviewers" aria-label="Permalink to &quot;Guidelines for _Reviewers_ &lt;a href=&quot;#guidelines-forreviewers&quot; id=&quot;guidelines-forreviewers&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><h4 id="be-polite-and-empathetic" tabindex="-1">Be polite and empathetic <a href="#be-polite-and-empathetic" id="be-polite-and-empathetic"></a> <a class="header-anchor" href="#be-polite-and-empathetic" aria-label="Permalink to &quot;Be polite and empathetic &lt;a href=&quot;#be-polite-and-empathetic&quot; id=&quot;be-polite-and-empathetic&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li>Avoid accusatory and/or judgmental comments like: “You should have done X”</li></ul><h4 id="provide-actionable-feedback" tabindex="-1">Provide <em>actionable</em> feedback <a href="#provideactionable-feedback" id="provideactionable-feedback"></a> <a class="header-anchor" href="#provide-actionable-feedback" aria-label="Permalink to &quot;Provide _actionable_ feedback &lt;a href=&quot;#provideactionable-feedback&quot; id=&quot;provideactionable-feedback&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li>Instead of <em>“This is bad”</em>, try <em>“I feel this could be clearer. What if you renamed variable X to Y?”</em></li></ul><h4 id="distinguish-between-requires-changes-and-nitpicks" tabindex="-1">Distinguish between “requires changes” and “nitpicks” <a href="#distinguish-between-requires-changes-and-nitpicks" id="distinguish-between-requires-changes-and-nitpicks"></a> <a class="header-anchor" href="#distinguish-between-requires-changes-and-nitpicks" aria-label="Permalink to &quot;Distinguish between “requires changes” and “nitpicks” &lt;a href=&quot;#distinguish-between-requires-changes-and-nitpicks&quot; id=&quot;distinguish-between-requires-changes-and-nitpicks&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li>Consider marking a PR as approved if the only requested changes are minor nits, so as not to block the author in another asynchronous review cycle.</li></ul><h4 id="respond-promptly-to-code-review-requests" tabindex="-1">Respond promptly to code review requests <a href="#respond-promptly-to-code-review-requests" id="respond-promptly-to-code-review-requests"></a> <a class="header-anchor" href="#respond-promptly-to-code-review-requests" aria-label="Permalink to &quot;Respond promptly to code review requests &lt;a href=&quot;#respond-promptly-to-code-review-requests&quot; id=&quot;respond-promptly-to-code-review-requests&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li>We’re a team – <a href="https://www.youtube.com/watch?v=1d5Q0vXbODs" target="_blank" rel="noreferrer"><em>we ride together, we die together</em></a> – and you need to unblock other developers so that we can all move forward.</li><li>We recommend checking for open code reviews at the start and end of every day.</li><li><a href="https://github.com/pulls/review-requested" target="_blank" rel="noreferrer">Github&#39;s Review Requests tab</a> can be a helpful place to keep track of these.</li></ul><h4 id="example-of-a-pretty-good-code-review" tabindex="-1">Example of a <em>pretty good</em> code review <a href="#example-of-apretty-goodcode-review" id="example-of-apretty-goodcode-review"></a> <a class="header-anchor" href="#example-of-a-pretty-good-code-review" aria-label="Permalink to &quot;Example of a _pretty good_ code review &lt;a href=&quot;#example-of-apretty-goodcode-review&quot; id=&quot;example-of-apretty-goodcode-review&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p><a href="https://github.com/getsentry/sentry/pull/5849" target="_blank" rel="noreferrer">getsentry/sentry#5849</a></p><ul><li>Submitted early as WIP to solicit feedback early</li><li>Reviewers respond same-day (once the WIP label is removed)</li><li>Reviewers are polite and complimentary</li><li>Feedback is objective and actionable</li><li>Submitter responds to feedback and makes changes promptly</li><li>PR is approved and merged within 48 hours</li></ul>`,90)])])}const g=t(o,[["render",s]]);export{p as __pageData,g as default};
